if @ky <> $ky.OldValue or @nam <> $nam.OldValue or @so_the_ts <> $so_the_ts.OldValue or @tk_kh <> $tk_kh.OldValue or @tk_cp <> $tk_cp.OldValue or @ma_bp_ts <> $ma_bp_ts.OldValue or @ma_kh <> $ma_kh.OldValue or @ma_vv <> $ma_vv.OldValue or @ma_bp <> $ma_bp.OldValue or @ma_hd <> $ma_hd.OldValue or @so_lsx <> $so_lsx.OldValue begin if exists(select * from @@table where (not (ky = $ky.OldValue and nam = $nam.OldValue and so_the_ts = $so_the_ts.OldValue and tk_kh = $tk_kh.OldValue and tk_cp = $tk_cp.OldValue and ma_bp_ts = $ma_bp_ts.OldValue and ma_kh = $ma_kh.OldValue and ma_vv = $ma_vv.OldValue and ma_bp = $ma_bp.OldValue and ma_hd = $ma_hd.OldValue and so_lsx = $so_lsx.OldValue)) and (ky = @ky and nam = @nam and so_the_ts = @so_the_ts and tk_kh = @tk_kh and tk_cp = @tk_cp and ma_bp_ts = @ma_bp_ts and ma_kh = @ma_kh and ma_vv = @ma_vv and ma_bp = @ma_bp and ma_hd = @ma_hd and so_lsx = @so_lsx)) begin select '' as field, @$exists as message return end end

script.text:
      /* <flatten type="Javascript"> */
function setFormFixedAssetAllocationCoefficient(f) {
  if (f._action != 'View') f._setReadOnly(f.getItem('so_the_ts'), f._action == 'Edit' && !f.getItemValue('dv_yn'));
  if (f._action == 'New') {
    f.setItemValue('ky', f.grid._period);
	  f.setItemValue('nam', f.grid._year);
  }
}
function loadForm$FixedAssetAllocationCoefficient(f) {f.add_onResponseComplete(on$FixedAssetAllocationCoefficient$ResponseComplete);}
function closingForm$FixedAssetAllocationCoefficient(f) {try {f.remove_onResponseComplete(on$FixedAssetAllocationCoefficient$ResponseComplete);} catch (ex) {}}
function onChangeFixedAssetAllocationCoefficient(o) {o.parentForm.request('FixedAsset', 'FixedAsset', ['so_the_ts'], o);}
function on$FixedAssetAllocationCoefficient$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'FixedAsset':
      f.setItemValue('tk_kh', result[0].Value);
      f.getItem('ten_tk_kh%l').value = result[1].Value;
      f.setItemValue('tk_cp', result[2].Value);
      f.getItem('ten_tk_cp%l').value = result[3].Value;
      break;
    default:
      break;
  }
}
/* </flatten> */
